{"id":"rust:tokio/src/runtime/scheduler/multi_thread/handle.rs#bind_new_task@81","source":"pub(super) fn bind_new_task<T>(
        me: &Arc<Self>,
        future: T,
        id: task::Id,
        spawned_at: SpawnLocation,
    ) -> JoinHandle<T::Output>
    where
        T: Future + Send + 'static,
        T::Output: Send + 'static,
